INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$30-plus 3D device mockups$q$, $q$A library covering iPhone, iPad, MacBook, and Android devices that screenshots or screen recordings can be dropped into and positioned in real-time 3D space.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Animated camera keyframes$q$, $q$Users set keyframes for camera position and on-screen content, and Rotato interpolates smooth rotate, float, or zoom animations automatically.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$High-resolution export$q$, $q$Video and image export up to 4K (Standard) or 8K (Premium), plus GIF and static PNG output for marketing and app store use.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$ProRes4444 and HEVC export$q$, $q$Premium-tier export formats with alpha-channel support for compositing device footage into Premiere, Final Cut, or After Effects projects.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Figma plugin$q$, $q$A Premium-tier plugin that lets designers pull screens directly from Figma into a Rotato 3D scene.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Clay render mode and lens controls$q$, $q$Premium-only stylistic rendering and camera lens adjustments for more cinematic or abstract mockup shots.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Prebuilt template gallery$q$, $q$Dozens of ready-made video and image templates that can be restyled with a brand's own screenshots rather than built from scratch.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$One-time lifetime licensing$q$, $q$All plans are sold as a single upfront payment rather than a recurring subscription, with a fixed window of included updates.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$No recurring subscription fee; pricing is a single one-time payment per tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Produces photorealistic 3D mockup videos without 3D design skills or software like Cinema 4D$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Large built-in library of devices and prebuilt templates speeds up production$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Supports professional export formats (ProRes4444, HEVC) for editing pipelines$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Self-funded, actively maintained product with a large existing install base$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Mac-only; no Windows or browser-based version is available$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$No permanent free tier, only a watermarked trial$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Full device library, templates, and 8K export require the higher-priced tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Advanced camera and animation customization has a learning curve for first-time users$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Is Rotato free to use?$q$, $q$Rotato has no permanent free tier. It offers a watermarked free trial so users can test the app before purchasing one of its one-time-payment license tiers, which start at $79.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Does Rotato work on Windows?$q$, $q$No. Rotato is built exclusively for macOS and has no native Windows or web-based version.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Is Rotato a subscription?$q$, $q$No. Rotato is sold as a one-time lifetime-license purchase across three tiers (Basic, Standard, Premium), each including a fixed window of free updates rather than ongoing monthly billing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$What export formats does Rotato support?$q$, $q$Rotato exports MP4, MOV, GIF, and static PNG files, with resolution up to 4K on Standard and 8K on Premium; Premium also adds ProRes4444 with alpha channel and HEVC/H.265.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$How many device mockups does Rotato include?$q$, $q$The Standard and Premium tiers include more than 30 device mockups spanning iPhone, iPad, MacBook, and Android hardware; the Basic tier is limited to phone mockups only.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Does Rotato integrate with Figma?$q$, $q$Yes, but only on the Premium plan, which includes a dedicated Figma plugin for pulling screens directly into a 3D scene.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Who makes Rotato?$q$, $q$Rotato was founded in 2019 by Morten, a former Google in-house incubator employee, and is a self-funded, profitable company based in Zurich, Switzerland.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Who is Rotato best suited for?$q$, $q$Rotato is aimed at SaaS founders, indie app developers, and design agencies who need App Store previews, Product Hunt launch visuals, or client UX presentation videos without hiring a 3D motion designer.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Product launch marketing visuals$q$, $q$Indie makers and SaaS founders use Rotato to create polished device mockup videos and images for Product Hunt launches, landing pages, and social posts.$q$, $q$Indie developers and SaaS founders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$App store preview videos$q$, $q$Mobile teams use Rotato to turn screen recordings into App Store and Google Play preview videos featuring realistic device frames.$q$, $q$Mobile app developers and marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Client UX presentation decks$q$, $q$Design agencies and freelancers use Rotato's animation presets and templates to deliver polished mockup reels for client pitches and case studies.$q$, $q$Design agencies and freelance designers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Basic$q$, $q$$79$q$, $q$one-time$q$, NULL, $q$["Phone mockups only","6 months of free updates","H.264 video export","No premium templates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Standard$q$, $q$$89$q$, $q$one-time$q$, NULL, $q$["All 30+ device mockups","1 in-app gallery template","18 premium video templates","12 months of free updates","4K export"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$Premium$q$, $q$$199$q$, $q$one-time$q$, NULL, $q$["100 premium video templates","50+ in-app gallery templates","2 premium website templates","8K export","ProRes4444 and HEVC/H.265 export","Figma plugin, clay mode, and camera lens control","12 months of free updates"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Rotato is a Mac-only application for creating 3D device mockups and animated product videos from ordinary screenshots or screen recordings. Founded in 2019 by former Google incubator employee Morten and based in Zurich, Switzerland, the company is self-funded, has never taken outside investment, and remains profitable while serving a global base of indie makers, marketers, and design agencies.$q$, $q$Instead of requiring specialized 3D software like Cinema 4D or After Effects, Rotato provides a real-time 3D engine with pre-built device models and animation presets, letting non-designers produce studio-quality mockup videos in minutes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Rotato ships with more than 30 photorealistic device mockups spanning iPhone, iPad, MacBook, and Android hardware, plus a library of prebuilt video and image templates that can be customized by dragging in a screenshot or screen recording. Users can freely rotate devices in 3D space, adjust lighting and backgrounds, and set camera keyframes for automatic rotate, float, or zoom animations.$q$, $q$Export options scale by plan, from standard H.264 video up to 4K and 8K resolution, with Premium adding ProRes4444 (including alpha channel) and HEVC/H.265 for professional post-production pipelines, along with a Figma plugin and clay-render mode.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fa4a289c-deca-4f77-9a17-9124d83266ee', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Rotato uses a one-time lifetime-license model rather than a subscription. The Basic tier costs $79 and covers phone mockups only with six months of included updates; Standard costs $89 and unlocks the full 30-plus device library with 12 months of updates and 4K export; Premium costs $199 and adds the full template library, 8K export, ProRes4444/HEVC, the Figma plugin, and clay mode.$q$, $q$There is no permanent free plan, but prospective buyers can try Rotato via a watermarked free trial before purchasing a license.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Full IMAP support$q$, $q$Complete IMAP protocol support for reading, organizing, and searching mail across folders on any standards-compliant mail server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Integrated address book$q$, $q$A built-in contacts manager for storing and organizing email addresses, synced alongside the webmail interface.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Skinnable, Ajax-driven interface$q$, $q$A desktop-like browser UI built with Ajax that can be restyled with custom skins for different branding or usability needs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Plugin API and extensibility$q$, $q$A documented plugin architecture that lets administrators add calendaring, two-factor authentication, spam controls, and other features.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$MIME and attachment handling$q$, $q$Full MIME support for viewing and sending attachments and multi-part messages reliably across mail clients.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Spell checking$q$, $q$Built-in spell checking powered by the Googiespell library, integrated directly into the message composer.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Self-hosted deployment$q$, $q$Runs on a standard LAMP/LEMP stack with no proprietary dependencies, giving organizations full control over their mail infrastructure.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Free, open-source licensing$q$, $q$Released under GNU GPL v3 or later, allowing free use, modification, and redistribution, with exceptions for skins and plugins.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Completely free and open source with no license fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$No vendor lock-in; runs on an organization's own IMAP/SMTP mail server$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Widely supported and bundled by major hosting control panels like cPanel and Plesk$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Extensible through a mature plugin ecosystem$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Long track record of active development since 2008$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Requires self-hosting and server administration knowledge unless bundled by a host$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Interface is more utilitarian than modern commercial webmail clients$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$No official vendor support; help typically comes from community forums or third-party contractors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Advanced features like calendaring require installing separate plugins$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Is Roundcube free?$q$, $q$Yes. Roundcube is free and open source under the GNU GPL v3 or later, with no license fees for the core software.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Who created Roundcube?$q$, $q$Roundcube was created by Thomas Bruederli, with the first stable release announced in March 2008 after about two years of development.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Is Roundcube a hosted email service?$q$, $q$No. Roundcube is a webmail client, not a mail hosting provider; it needs to be installed on a server and connected to an existing IMAP/SMTP mail server.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$What happened to Roundcube Next?$q$, $q$Roundcube Next was a planned full rewrite announced with Kolab Systems in 2015 and funded via a crowdfunding campaign that raised over $103,000, but the rewrite effort was halted in 2016.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Who maintains Roundcube today?$q$, $q$Since 2023, the Roundcube project's organizational and fiscal home has been hosted under Nextcloud, alongside its original community of contributors.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Can Roundcube be extended with plugins?$q$, $q$Yes, Roundcube has a documented plugin API that allows features like calendaring, two-factor authentication, and custom branding to be added.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$What server stack does Roundcube require?$q$, $q$Roundcube runs on a standard LAMP or LEMP stack: Linux, a web server like Apache or Nginx, a database such as MySQL or PostgreSQL, and PHP.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Why do many hosting providers include Roundcube?$q$, $q$Because it is free, self-hosted, and lightweight, hosting panels such as cPanel adopted Roundcube as a bundled webmail option, replacing older clients like SquirrelMail.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Shared hosting webmail$q$, $q$Web hosting providers bundle Roundcube as the default browser-based email client for customers using cPanel, Plesk, or similar control panels.$q$, $q$Web hosting companies and their customers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Self-hosted organizational email$q$, $q$Businesses, universities, and ISPs running their own IMAP mail servers deploy Roundcube as a free front end instead of paying for a commercial webmail suite.$q$, $q$IT administrators at organizations running their own mail servers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Privacy-focused email setups$q$, $q$Privacy-conscious individuals and organizations pair Roundcube with self-hosted mail servers to avoid third-party webmail providers entirely.$q$, $q$Privacy-focused individuals and small organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$Open Source (self-hosted)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full IMAP webmail interface","Address book and folder management","Plugin API for extensions","GNU GPL v3 or later license","Community-driven support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Roundcube is an open-source, PHP-based webmail client that gives any IMAP mail server a modern, AJAX-driven browser interface. First released as a stable version in March 2008 after development led by founder Thomas Bruederli, it has since become one of the most widely deployed self-hosted webmail front ends, bundled by default with hosting control panels such as cPanel and Plesk.$q$, $q$The project is licensed under GNU GPL v3 or later and has been fiscally and organizationally hosted under Nextcloud since 2023, following an earlier attempt at a full rewrite (Roundcube Next) with Kolab Systems that was funded via crowdfunding in 2015 but halted in 2016.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Roundcube supports full IMAP functionality including folder management, message search, spell checking, and MIME-compliant attachment handling, along with an integrated address book and a skinnable, desktop-like interface built on Ajax.$q$, $q$A documented plugin API allows administrators to extend Roundcube with features like calendaring, two-factor authentication, and custom branding, and the project bundles other open-source libraries such as TinyMCE for rich text editing and an HTML5-PHP sanitizer for security.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Roundcube itself is completely free and open source under the GNU GPL; there is no official paid tier, subscription, or per-seat license fee for the core software.$q$, $q$Organizations typically incur only hosting infrastructure costs, since Roundcube runs on a standard LAMP/LEMP stack; some managed hosting providers and hosting panels bundle Roundcube automatically as part of paid hosting plans, but that cost is for the hosting itself, not for a Roundcube license.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb4553dc-a02b-4c01-a2c6-6a0dc57786d4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Unified tasks, calendar, and notes$q$, $q$A single workspace combining task lists, a synced calendar, and note-taking so users do not need separate apps for each.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$AI assistant and voice commands$q$, $q$Built-in AI that helps draft tasks and notes and responds to voice commands, available even on the free plan with a monthly credit allotment.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$AI meeting notes and agents$q$, $q$Professional and above plans include AI-generated meeting notes and AI agents that can automate parts of a user's workflow.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Calendar integrations$q$, $q$Two-way sync with Google Calendar, with Outlook and iCloud Calendar integration also supported.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Time blocking and time tracking$q$, $q$Tools for scheduling focused work blocks and tracking actual time spent on tasks, available from the Personal and Professional tiers respectively.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Custom databases$q$, $q$Configurable custom databases for structuring information beyond standard tasks and notes, with limits that expand by plan tier.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Cross-platform sync$q$, $q$Native apps for macOS, Windows, web, and iOS keep tasks, calendar events, and notes synchronized across devices.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Team workspaces and access control$q$, $q$Business-tier features including shared organization workspaces, permissioned access control, versioning, and consolidated billing for teams.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Combines calendar, tasks, and notes in one app instead of three separate tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Generous free tier includes AI assistant features and multiple integrations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Y Combinator-backed startup with active development and funding$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Cross-platform coverage across macOS, Windows, web, and iOS$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Transparent, relatively low-cost individual pricing tiers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Android app support has lagged behind other platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$AI features are metered by monthly credits that can run out on lower tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Smaller company size than legacy competitors like Notion or Todoist, which may affect long-term support and roadmap pace$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Business and Enterprise pricing requires per-seat or custom budgeting for teams$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Is Routine free to use?$q$, $q$Yes, Routine offers a free plan for individuals that includes tasks, calendar, notes, a basic AI assistant, three integrations, and 250 monthly AI credits.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$How much does Routine cost for individuals?$q$, $q$Paid individual plans are Personal at $5/month and Professional at $10/month, both billed monthly and cancelable anytime.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Does Routine have a team plan?$q$, $q$Yes, the Business plan costs $15 per seat per month and adds shared workspaces, access control, and consolidated billing; an Enterprise plan with custom pricing is also available.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Who founded Routine?$q$, $q$Routine was founded in 2020 in Paris, France by Quentin Hocquet and Julien Quintard, and went through Y Combinator's Winter 2021 batch.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$What calendars does Routine sync with?$q$, $q$Routine integrates with Google Calendar natively, with support for Microsoft Outlook and iCloud Calendar also available.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Does Routine work on Android?$q$, $q$Routine has historically prioritized macOS, Windows, web, and iOS, with Android support noted as in-progress in the company's public roadmap.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$What are Routine's AI credits?$q$, $q$AI credits are a monthly usage allotment that powers Routine's AI assistant, meeting notes, and automation features; the allotment scales up with each paid plan tier.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Has Routine raised funding?$q$, $q$Yes, Routine raised a $2.7 million pre-seed round from investors including BoxGroup and Target Global, alongside participation from several angel investors.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Daily planning for knowledge workers$q$, $q$Individuals use Routine's Agenda and Tasks views to plan their day across meetings, unplanned to-dos, and recurring responsibilities in one place.$q$, $q$Knowledge workers and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Consolidating productivity tools$q$, $q$Users replace separate calendar, task manager, and notes apps with Routine's unified workspace to reduce app-switching and subscription sprawl.$q$, $q$Individuals and small teams standardizing on fewer tools$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Team scheduling and workflow coordination$q$, $q$Small teams use Routine's Business plan for shared workspaces, access control, and consolidated billing to coordinate tasks and meetings together.$q$, $q$Small to mid-size teams and startups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Free$q$, $q$$0$q$, $q$forever$q$, NULL, $q$["Tasks, calendar, and notes","AI assistant and AI voice commands","Offline mode","3 integrations","3 custom databases","250 AI credits per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Personal$q$, $q$$5$q$, $q$per month$q$, NULL, $q$["Everything in Free","Time blocking and time boxing","Exporting","Unlimited file uploads","10 integrations","10 custom databases","500 AI credits per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Professional$q$, $q$$10$q$, $q$per month$q$, NULL, $q$["Everything in Personal","AI meeting notes","AI agents and automations","Menu bar widget","Time tracking","Contextual capture","Unlimited integrations and custom databases","7,000 AI credits per month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Business$q$, $q$$15$q$, $q$per seat per month$q$, NULL, $q$["Everything in Professional","Organization-wide workspaces","Access control","Versioning","Consolidated billing","Priority support","10,000 AI credits per seat"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$Enterprise$q$, $q$Custom$q$, $q$contact for quote$q$, NULL, $q$["Everything in Business","Unlimited history","Compliance controls","Audit logs","Analytics","User provisioning","Dedicated success manager"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Routine is a Paris-based productivity app, founded in 2020 by Quentin Hocquet and Julien Quintard and graduated from Y Combinator's W21 batch, that combines calendar, task management, and note-taking into a single AI-assisted workspace rather than requiring users to juggle separate apps.$q$, $q$The product syncs with external calendars such as Google Calendar and organizes work around an Inbox, Agenda, Calendar, Tasks, and Notes structure, with AI features layered on top for meeting notes, automations, and voice commands.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include a quick-capture Inbox, a daily Agenda view, two-way calendar sync, a structured task list separating unplanned, recurring, and upcoming items, and a dedicated notes workspace, all synced across macOS, Windows, web, and iOS.$q$, $q$Paid tiers add AI meeting notes, AI agents and automations, time tracking, time blocking and boxing, unlimited integrations and custom databases, and, for teams, workspace-level access control and consolidated billing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00e620ce-3d58-4944-af9e-bc0f5e8779e6', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Routine offers a free-forever individual plan, then paid individual tiers at $5/month (Personal) and $10/month (Professional), each unlocking more integrations, AI credits, and automation features, all cancelable at any time.$q$, $q$Team pricing starts at $15 per seat per month for the Business plan, with a custom-quoted Enterprise plan for larger organizations needing compliance, audit logging, and dedicated account management.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$SIP proxy, registrar, and location server$q$, $q$Implements the three core SIP server roles needed to route, register, and locate endpoints in a VoIP network.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Docker and Kubernetes native$q$, $q$Ships as a Docker image and can be deployed to Kubernetes via Helm, designed for cloud-native infrastructure from the ground up.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$RESTful API and CLI control$q$, $q$Supports remote administration through a command-line tool, a RESTful API, or a web-based GUI for teams that prefer point-and-click management.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Configurable routing strategies$q$, $q$Supports Intra-Domain, Domain Ingress, Domain Egress, and Peer Egress routing patterns for flexible call routing logic.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Multi-tenant, multi-domain support$q$, $q$Domain-level access control lists allow a single Routr deployment to serve multiple tenants or customer domains securely.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Extensible via Processors and Middleware$q$, $q$A modular plugin-style architecture lets developers write custom Processors and Middleware to extend or override default server behavior.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Open-source and self-hosted$q$, $q$Fully open-source codebase available on GitHub, allowing organizations to inspect, modify, and self-host without licensing fees.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Free and open source with no licensing cost for the software$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Cloud-native design that deploys cleanly on Docker and Kubernetes$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Multiple control interfaces (CLI, REST API, GUI) suit different operational preferences$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Extensible architecture for teams with custom SIP routing requirements$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Built by Fonoster, a team focused on open-source communications infrastructure$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Requires SIP and telephony infrastructure expertise to deploy and operate safely$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$No official managed/hosted SaaS version documented, so operations burden falls on the deploying team$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Smaller community and ecosystem compared to established commercial SBC and SIP server vendors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Corporate details about the maintaining company are not consistently documented publicly$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$What is Routr used for?$q$, $q$Routr is used to build and operate SIP-based VoIP infrastructure, acting as a proxy, registrar, and location server for telephony carriers, service providers, and integrators.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Is Routr free?$q$, $q$Yes, Routr is free and open source; there is no license fee for the software itself, only the cost of the infrastructure used to run it.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Who develops Routr?$q$, $q$Routr is developed by Fonoster, a team also known for building an open-source alternative to Twilio's communications APIs.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Does Routr run on Kubernetes?$q$, $q$Yes, Routr is designed to be cloud-native and can be deployed to Kubernetes using Helm, in addition to running on Docker or directly on major operating systems.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$How is Routr different from a router hardware product?$q$, $q$Routr is unrelated to networking router hardware; it is software that performs SIP proxy, registrar, and location-server functions for VoIP call routing, not physical network traffic routing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Can Routr be controlled programmatically?$q$, $q$Yes, Routr exposes a RESTful API for programmatic control in addition to a command-line interface and a web-based GUI.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Is Routr suitable for beginners?$q$, $q$Routr assumes familiarity with SIP and telephony concepts; it is aimed at engineers and integrators building VoIP infrastructure rather than non-technical users.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Self-hosted VoIP carrier infrastructure$q$, $q$Telephony carriers and communication service providers deploy Routr as their SIP proxy and registrar to avoid the cost of commercial session border controllers.$q$, $q$Telephony carriers and communication service providers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Cloud-native SIP deployments$q$, $q$Engineering teams deploy Routr on Kubernetes or Docker to run scalable, containerized SIP infrastructure alongside other cloud-native services.$q$, $q$DevOps and infrastructure engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Custom call routing logic$q$, $q$Integrators extend Routr with custom Processors and Middleware to implement specialized routing rules for enterprise or multi-tenant SIP deployments.$q$, $q$VoIP integrators and platform engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$Open Source (self-hosted)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["SIP proxy, registrar, and location server","Docker and Kubernetes deployment","RESTful API, CLI, and web GUI control","Multi-tenant, multi-domain support","Extensible via custom Processors and Middleware"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Routr is an open-source SIP proxy, registrar, and location server built by Fonoster for teams that need to run their own VoIP or telephony infrastructure. It is designed to be cloud-native, running on Docker and Kubernetes as well as traditional operating systems, and is published as open-source code on GitHub under fonoster/routr.$q$, $q$The project targets telephony carriers, communication service providers, and integrators who want a lightweight, programmable SIP server instead of a heavyweight commercial session border controller or SIP trunking platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Routr implements the core SIP server functions of Proxy, Registrar, and Location Service, with configurable routing strategies for intra-domain, domain ingress, domain egress, and peer egress traffic, plus multi-tenant support with domain-level access control lists.$q$, $q$It can be controlled via a command-line interface, a RESTful API, or a web-based GUI, and its modular architecture allows developers to extend behavior with custom Processors and Middleware rather than being confined to built-in functionality.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Routr is free and open source; there is no licensing fee to download, self-host, and modify the software. Costs to an organization are limited to the infrastructure used to run it, such as cloud compute for Docker or Kubernetes deployments.$q$, $q$There is no separate commercial SaaS tier of Routr documented on routr.io; organizations needing managed communications infrastructure would instead look at Fonoster's broader open-source communications platform.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Unlimited episodes and storage$q$, $q$Every plan, including the free tier, allows unlimited podcast episodes and unlimited audio storage with no length caps.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Automatic directory distribution$q$, $q$Podcasts are automatically distributed to major platforms including Spotify, Apple Podcasts, and Amazon Music from a single RSS feed.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Dynamic ad insertion monetization$q$, $q$Paid plans let shows monetize with dynamic ad insertion starting from as few as 10 downloads per episode.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$AI-generated transcripts$q$, $q$Automatic AI-powered episode transcripts are available on paid plans, useful for accessibility and SEO.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Podcast website and embeddable player$q$, $q$Every plan includes an auto-generated podcast website and a customizable embeddable player for sharing episodes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Value for Value and listener donations$q$, $q$Built-in support for listener donations and Value-for-Value monetization models, available even on the free plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Audio-to-video YouTube conversion$q$, $q$Paid plans can automatically convert audio episodes into video files formatted for YouTube distribution.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Team and multi-show management$q$, $q$The Podcast Networks plan supports unlimited shows and team seats with API access for managing a portfolio of podcasts.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Unlimited episodes and storage available even on the permanently free plan$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Built-in monetization tools like dynamic ad insertion and listener donations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Automatic distribution to all major podcast directories$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Affordable annual pricing compared to several competitors$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Includes AI transcripts and audio-to-video conversion on paid tiers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Lower-cost pricing shown on the site is tied to annual billing, so monthly billing costs more$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Advanced monetization features are locked behind paid plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Smaller company than legacy podcast hosts, which may mean a smaller support and integration ecosystem$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Podcast Networks-level features like API access require the top-tier plan$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Is RSS.com free?$q$, $q$Yes, RSS.com offers a permanently free Local and Niche plan with unlimited episodes and storage, no credit card required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$How much does RSS.com cost?$q$, $q$Paid plans start at $11.99/month for the All in One Podcasting plan when billed annually, with the Podcast Networks plan at $18.75/month billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Does RSS.com support podcast monetization?$q$, $q$Yes, paid plans include dynamic ad insertion available from as few as 10 downloads per episode, Apple Podcasts Subscriptions support, and Value-for-Value listener donations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Does RSS.com distribute to Spotify and Apple Podcasts?$q$, $q$Yes, all plans include automatic distribution to major podcast directories including Spotify, Apple Podcasts, and Amazon Music.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Can RSS.com convert podcasts to video?$q$, $q$Yes, paid plans include audio-to-video conversion for publishing episodes as YouTube videos.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Does RSS.com offer transcripts?$q$, $q$Yes, AI-generated transcripts are available on paid plans, with automatic transcripts included at the Podcast Networks tier.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Is RSS.com good for podcast networks?$q$, $q$Yes, the Podcast Networks plan supports unlimited shows, unlimited team seats, unlimited analytics, and API access for managing multiple shows.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$When was RSS.com launched?$q$, $q$The RSS.com domain existed earlier, but the company built out and launched its current podcast hosting platform around 2018.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Launching a free podcast$q$, $q$Hobbyist and niche creators use RSS.com's free plan to publish unlimited episodes with distribution and basic analytics at no cost.$q$, $q$Hobbyist and independent podcasters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Monetizing a growing show$q$, $q$Established podcasters upgrade to the All in One plan to unlock dynamic ad insertion, subscriptions, and listener donations.$q$, $q$Growing independent podcasters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Managing a podcast network$q$, $q$Networks with multiple shows use the Podcast Networks plan for unlimited shows, team seats, and API access to manage everything centrally.$q$, $q$Podcast networks and production companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Local and Niche$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Unlimited episodes and audio","Public RSS feed and embeddable player","Podcast website","Episode scheduling and transcripts","Basic analytics","Automatic directory distribution","Listener donations and Value for Value monetization","Copyright protection","Human support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$All in One Podcasting$q$, $q$$11.99/month$q$, $q$billed annually$q$, NULL, $q$["Everything in Local and Niche","Dynamic ad insertion monetization from 10 downloads","Apple Podcasts Subscriptions earnings","Audio-to-video YouTube conversion","Team member invitations","Unbranded player","AI-generated transcripts","Advanced analytics","Exclusive Slack community access","Priority customer support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$Podcast Networks$q$, $q$$18.75/month$q$, $q$billed annually$q$, NULL, $q$["Everything in All in One Podcasting","Unlimited podcasts and team seats","Unlimited podcast analytics","API access","Automatic transcripts","Unbranded YouTube videos"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RSS.com is a podcast hosting and monetization platform built to let creators launch a show, distribute it to major podcast directories, and eventually monetize it through ads, subscriptions, and listener donations, all from one dashboard. The current product was built out and launched around 2018, and the company is based in the United States with a team of roughly 50 people as of recent reporting.$q$, $q$The platform is positioned as a budget-friendly alternative to established podcast hosts, most notably by offering unlimited episodes and unlimited audio storage even on its permanently free plan.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$All RSS.com plans, including the free tier, include unlimited episodes, unlimited storage, automatic distribution to directories like Spotify and Apple Podcasts, a podcast website, an embeddable player, and episode scheduling.$q$, $q$Paid plans add monetization tools such as dynamic ad insertion from as few as 10 downloads, Apple Podcasts Subscriptions support, listener donations, AI-generated transcripts, audio-to-video YouTube conversion, and advanced or unlimited analytics depending on tier.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('486dac3f-e396-4ba6-9c6e-20a5f563c673', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The free Local and Niche plan requires no credit card and includes unlimited episodes and storage plus basic distribution and analytics. The All in One Podcasting plan costs $11.99/month billed annually and adds monetization and team features.$q$, $q$The top Podcast Networks plan costs $18.75/month billed annually and is built for managing unlimited podcasts and team seats with unlimited analytics and API access, targeting podcast networks rather than single-show creators.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$1,000-plus pre-built content routes$q$, $q$A large library of code-defined routes that generate RSS feeds from social media, news, e-commerce, video, and other web sources lacking native feeds.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Self-hosting via Docker or npm$q$, $q$RSSHub can be deployed on a user's own server using the official Docker image or npm package for full control over uptime and rate limits.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Free public community instances$q$, $q$Thousands of publicly run RSSHub instances let users subscribe to generated feeds without hosting anything themselves.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$RSSHub Radar browser extension$q$, $q$A companion browser extension that automatically detects RSS and RSSHub-compatible feeds on the page a user is viewing for one-click subscription.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Mobile companion apps$q$, $q$RSSBud for iOS and RSSAid for Android extend RSSHub Radar's feed-discovery functionality to mobile devices.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Open, community-driven route contributions$q$, $q$Over 900 contributors maintain and expand the route library, with a documented process for adding new source routes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$AGPL-3.0 open-source license$q$, $q$The full source code is publicly available and licensed under AGPL-3.0, allowing inspection, modification, and self-hosted deployment.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Completely free with no paid tier or usage fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Massive route library covering over 1,000 distinct content sources$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Active, large open-source community with 45,000-plus GitHub stars$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Flexible deployment via self-hosting or free public instances$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Companion browser extension and mobile apps simplify feed discovery$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$No official company or support contract; help comes from community channels$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Public instances can be rate-limited or unreliable compared to self-hosting$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Self-hosting requires server administration and Docker or Node.js familiarity$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Some routes can break when source websites change their structure, requiring community fixes$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Is RSSHub free?$q$, $q$Yes, RSSHub is completely free and open source under the AGPL-3.0 license, with no paid tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Who created RSSHub?$q$, $q$RSSHub was created and is primarily maintained by developer DIYgod, with contributions from a community of more than 900 contributors.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Do I need to self-host RSSHub?$q$, $q$No, RSSHub can be used via one of thousands of free public community instances, though self-hosting via Docker or npm gives more control and reliability.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$How many sources does RSSHub support?$q$, $q$RSSHub includes more than 1,000 pre-built routes covering social media, news, e-commerce, video platforms, and many other categories of websites.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$What license does RSSHub use?$q$, $q$RSSHub is released under the AGPL-3.0 open-source license.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Is there a browser extension for RSSHub?$q$, $q$Yes, RSSHub Radar is a browser extension that detects RSS and RSSHub-compatible feeds on the current page for one-click subscription.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Is RSSHub different from RSS.com?$q$, $q$Yes, RSSHub is a free open-source RSS feed generator for sites without native feeds, while RSS.com is an unrelated paid podcast hosting company; they share no ownership or history.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$How large is the RSSHub community?$q$, $q$RSSHub describes itself as the world's largest RSS network with over 5,000 public instances and has more than 45,000 stars on GitHub.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Tracking sources without native RSS$q$, $q$Developers and researchers use RSSHub to generate feeds for social media accounts, government notices, or niche sites that never offered RSS.$q$, $q$Developers, researchers, and power users of RSS readers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Self-hosted content monitoring stacks$q$, $q$Privacy-focused users self-host RSSHub alongside a self-hosted RSS reader to build a fully independent content-tracking pipeline.$q$, $q$Self-hosting enthusiasts and privacy-focused users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Journalism and OSINT source monitoring$q$, $q$Journalists and researchers use RSSHub routes to monitor updates from social accounts, forums, and listings relevant to ongoing reporting or investigations.$q$, $q$Journalists and open-source researchers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$Open Source (self-hosted or public instance)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["1,000+ pre-built content routes","Self-hosting via Docker or npm","Access to thousands of free public instances","RSSHub Radar browser extension support","AGPL-3.0 open-source license"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RSSHub is an open-source project created by developer DIYgod that generates RSS feeds for websites and services that do not offer one natively, addressing the broader decline of native RSS support across the modern web.$q$, $q$The project is released under the AGPL-3.0 license, hosted at github.com/DIYgod/RSSHub, and has grown into what its own documentation describes as the world's largest RSS network, with over 5,000 public community-run instances and more than 1,000 pre-built content routes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$RSSHub's core feature is its library of over 1,000 routes, each a small piece of code that scrapes or queries a specific website or service and outputs the result as a standards-compliant RSS feed that any feed reader can subscribe to.$q$, $q$The ecosystem also includes RSSHub Radar, a browser extension for auto-detecting subscribable feeds on the current page, plus mobile companion apps RSSBud (iOS) and RSSAid (Android) for discovering and managing RSSHub-generated feeds on mobile.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$RSSHub is entirely free and open source under the AGPL-3.0 license; there is no paid tier, subscription, or commercial edition of the software itself.$q$, $q$Users can self-host RSSHub at no software cost beyond their own server infrastructure, or use one of the many free public instances run by community members, which trade guaranteed uptime for zero setup effort.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('97ffdc76-9598-495d-a32e-3ec8c21cde65', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Warehouse-native architecture$q$, $q$Runs data collection, identity resolution, and activation directly on the customer's own warehouse (Snowflake, BigQuery, Databricks, Redshift) instead of a proprietary data store.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$16-plus SDK sources$q$, $q$Event collection SDKs across web, mobile, and server-side environments for capturing first-party customer data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$200-plus cloud destinations$q$, $q$Pre-built integrations that route collected event data to marketing, analytics, and advertising tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Reverse ETL$q$, $q$Syncs data already modeled in the warehouse back out to operational and go-to-market tools, activating warehouse data for business teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Configurable data transformations$q$, $q$Lets teams clean, filter, or enrich event data in transit, with transformation limits that expand by plan tier.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Tracking plans$q$, $q$Schema governance tooling that lets teams define and enforce expected event structures across sources.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Enterprise security and compliance$q$, $q$HIPAA compliance, single sign-on, and VPC deployment options available on the Enterprise plan for regulated or security-sensitive organizations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Open-source core$q$, $q$RudderStack's core technology has open-source roots, giving engineering teams the option to self-host rather than use the managed cloud service exclusively.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Warehouse-native model keeps first-party customer data under the company's own control$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Generous free tier covering up to 250,000 events per month$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Open-source option available for teams that prefer self-hosting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Wide destination coverage with over 200 integrations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Reverse ETL is built in rather than requiring a separate tool$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Pricing scales with event volume, which can grow costly at high traffic levels$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Enterprise-grade features like fast warehouse sync and SSO require custom Enterprise pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Warehouse-native model assumes the customer already has a modern cloud data warehouse in place$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Smaller company size than legacy CDP competitors, which may affect support scale$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Is RudderStack free?$q$, $q$Yes, RudderStack offers a free plan supporting up to 250,000 events per month with access to core sources, destinations, and reverse ETL.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$How much does RudderStack cost?$q$, $q$The Growth plan starts at $265/month for up to 1 million events, scalable to 25 million or more, with a 15 percent discount for annual billing; Enterprise pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Is RudderStack open source?$q$, $q$RudderStack has open-source roots and offers a self-hosted option alongside its managed commercial cloud service.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$What is warehouse-native customer data platform architecture?$q$, $q$It means collection, identity resolution, and activation run directly on the customer's own data warehouse, such as Snowflake or BigQuery, instead of copying data into a separate vendor-owned store.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Who founded RudderStack?$q$, $q$RudderStack was founded in July 2019 by CEO Soumyadeb Mitra and Executive Chairman Shvetank Jain, and is headquartered in San Francisco.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Does RudderStack support reverse ETL?$q$, $q$Yes, reverse ETL is a built-in feature that syncs warehouse-modeled data back out to operational and marketing tools.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$How many destinations does RudderStack integrate with?$q$, $q$RudderStack supports more than 200 cloud destinations for routing collected customer event data.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Is RudderStack HIPAA compliant?$q$, $q$HIPAA compliance support is available on RudderStack's custom-priced Enterprise plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$First-party data collection at scale$q$, $q$Product and data engineering teams use RudderStack's SDKs to collect first-party event data across web, mobile, and server platforms into their own warehouse.$q$, $q$Data engineering and product analytics teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Marketing and sales activation via reverse ETL$q$, $q$Growth and marketing teams use RudderStack's reverse ETL to sync warehouse-modeled customer segments back into ad platforms and CRM tools.$q$, $q$Marketing operations and RevOps teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Regulated-industry customer data infrastructure$q$, $q$Enterprises in healthcare and other regulated industries use RudderStack's Enterprise plan for HIPAA-compliant, VPC-deployed customer data pipelines.$q$, $q$Enterprise and regulated-industry data teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Free$q$, $q$$0$q$, $q$forever$q$, NULL, $q$["Up to 250,000 events/month","16 SDK sources","200+ cloud destinations","Warehouse destinations and reverse ETL","1 tracking plan","5 transformation limit","Up to 10 team members","1 production workspace"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Growth$q$, $q$$265/month$q$, $q$monthly (15 percent discount with annual commitment)$q$, NULL, $q$["Up to 1M events/month, scalable to 25M+","Unlimited team members and tracking plans","30-minute warehouse sync","2 workspaces","25 reverse ETL connections","25 transformation limit","Advanced consent integration","Dedicated Slack support","Up to 6 months onboarding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$Enterprise$q$, $q$Custom$q$, $q$contact sales$q$, NULL, $q$["Everything in Growth","5-minute warehouse sync","Unlimited transformations","Profiles and Data Apps access","HIPAA compliance","SSO authentication","VPC deployment","White-glove support with TAM, CSM, and Solutions Architect"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RudderStack is a warehouse-native customer data platform founded in July 2019 by Soumyadeb Mitra and Shvetank Jain and headquartered in San Francisco. Its defining architectural choice is running data collection, identity resolution, and activation directly on a customer's own warehouse, such as Snowflake, BigQuery, Databricks, or Redshift, rather than duplicating data into a proprietary vendor-hosted store.$q$, $q$The platform has open-source roots and continues to offer both a self-hosted open-source option and a fully managed commercial cloud service, appealing to engineering-led teams that want more control over their customer data infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include event collection via 16-plus SDKs across web, mobile, and server platforms, routing to more than 200 cloud destinations, and reverse ETL for syncing warehouse-modeled data back out to operational tools.$q$, $q$Higher tiers add faster warehouse sync intervals, unlimited data transformations, identity resolution features under RudderStack's Profiles product, and enterprise security options including HIPAA compliance, SSO, and VPC deployment.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$RudderStack's Free plan covers up to 250,000 events per month with access to core sources, destinations, and reverse ETL at no cost. The Growth plan starts at $265/month for up to 1 million events, with a 15 percent discount for annual billing and scalability to 25 million-plus events.$q$, $q$The Enterprise plan is custom-priced and adds 5-minute warehouse sync, unlimited transformations, HIPAA compliance, SSO, VPC deployment, and dedicated technical and customer success support for large organizations.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db57c4c5-6372-4dcb-8aeb-de596d7f6b20', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Cron-style and event-driven job scheduling$q$, $q$Supports both traditional cron-syntax scheduled jobs and event-driven triggers for reactive automation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Multi-step workflow engine$q$, $q$Handles complex operational processes with conditional logic, error handling, retry mechanisms, and parallel step execution.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Self-service access delegation$q$, $q$Lets administrators grant specific users or teams the ability to run predefined jobs without full underlying system access.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Certified enterprise plugins$q$, $q$Enterprise tier includes certified integrations with tools such as PagerDuty, ServiceNow, and Datadog for connected incident and change workflows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$High-availability clustering$q$, $q$Enterprise and SaaS tiers support HA clustering with auto-takeover to keep automation running during node failures.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Visual workflow builder$q$, $q$A GUI-based workflow visualization and configuration tool available on the Enterprise and SaaS tiers for building jobs without hand-writing definitions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Activity logging and key storage$q$, $q$Built-in audit logging of job executions and secure key storage for credentials, available even in the free Community Edition.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$AI-assisted runbook generation$q$, $q$The managed PagerDuty Process Automation SaaS tier includes AI-generated runbook suggestions and ROI metrics for automation initiatives.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Free, open-source Community Edition available for teams that want to self-host at no cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Backed by PagerDuty's incident-response ecosystem and integrations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Mature product with a long track record dating back to 2010$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Supports both self-hosted and fully managed SaaS deployment models$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Used by many Fortune 500 companies, indicating enterprise-grade reliability at scale$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Enterprise and SaaS pricing is not published and requires contacting sales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Community Edition lacks high availability, SSO, and certified plugins found in paid tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Reported average enterprise contract value (~$51,000/year) is a significant cost for smaller teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Now fully owned by PagerDuty, so its roadmap is tied to PagerDuty's broader product strategy rather than operating independently$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Is Rundeck free?$q$, $q$Yes, Rundeck's Community Edition is free and open source, though it lacks enterprise features like high availability, SSO, and certified plugins found in the paid Enterprise and SaaS tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Who owns Rundeck?$q$, $q$Rundeck is owned by PagerDuty, which acquired it on October 1, 2020 for approximately $100 million in cash and stock; it is now marketed as PagerDuty Process Automation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$How much does Rundeck Enterprise cost?$q$, $q$Enterprise and SaaS pricing is not publicly listed and requires a custom quote from PagerDuty sales; third-party sources report average enterprise contracts around $51,000 per year.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$When was Rundeck founded?$q$, $q$Rundeck was first released in 2010 by SimplifyOps, a company founded by Damon Edwards, Alex Honor, and Greg Schueler.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$What is Rundeck used for?$q$, $q$Rundeck is used for runbook automation and job scheduling, letting operations and DevOps teams automate and delegate routine tasks like deployments, restarts, and incident remediation.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Does Rundeck support Kubernetes and cloud infrastructure?$q$, $q$Yes, Rundeck is commonly used to automate tasks across distributed and cloud infrastructure, and integrates with tools such as Datadog and ServiceNow via certified plugins on the Enterprise tier.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$What is the difference between Rundeck Community and Enterprise?$q$, $q$Community is free and open source with core scheduling and workflow features, while Enterprise adds high-availability clustering, SSO, certified plugins, a visual workflow builder, and job queuing for scale.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Is there a managed, hosted version of Rundeck?$q$, $q$Yes, PagerDuty offers a fully managed SaaS edition called PagerDuty Process Automation, which includes a 99.9 percent uptime SLA and AI-assisted runbook generation.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Automating routine IT operations$q$, $q$Operations teams use Rundeck to automate repetitive maintenance tasks like server restarts, backups, and deployments on a schedule.$q$, $q$IT operations and infrastructure teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Delegated, self-service job execution$q$, $q$Organizations use Rundeck's access controls to let non-admin staff run predefined jobs safely without granting full production system access.$q$, $q$DevOps and platform engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Incident remediation runbooks$q$, $q$SRE teams pair Rundeck with PagerDuty's incident response tools to automate remediation steps triggered during an active incident.$q$, $q$Site reliability engineering (SRE) teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$Community Edition (Open Source)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Core workflow execution","Community plugins","Encryption","Job scheduling","Activity logging","Key storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$PagerDuty Process Automation Self-Hosted (Enterprise)$q$, $q$Custom$q$, $q$contact sales$q$, NULL, $q$["Everything in Community Edition","High-availability clustering with auto-takeover","Single sign-on authentication","Certified enterprise plugins (PagerDuty, ServiceNow, Datadog, and more)","Enhanced rule-based webhooks","Workflow visualization and configuration GUI","Job queuing and load balancing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$PagerDuty Process Automation (SaaS)$q$, $q$Custom$q$, $q$contact sales$q$, NULL, $q$["Everything in Self-Hosted Enterprise","Fully managed by PagerDuty","99.9 percent uptime SLA","AI-generated runbook suggestions","Automation ROI metrics"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Rundeck is runbook automation and job scheduling software first released in 2010 by SimplifyOps, a company founded by Damon Edwards, Alex Honor, and Greg Schueler, and acquired by PagerDuty on October 1, 2020 for approximately $100 million in cash and stock.$q$, $q$The product turns manual operational runbooks into repeatable, self-service automations that let operations, DevOps, and SRE teams execute standardized tasks like deployments and remediations without granting broad production access.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Rundeck's job scheduling supports cron-style schedules and event-driven triggers, and its workflow engine handles multi-step processes with conditional logic, error handling, retries, and parallel execution across distributed infrastructure.$q$, $q$Enterprise and SaaS tiers add high-availability clustering, single sign-on, certified plugins for tools like ServiceNow and Datadog, a visual workflow builder, job queuing and load balancing, and, more recently, AI-assisted runbook generation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The Community Edition of Rundeck is free and open source, covering core workflow execution, scheduling, community plugins, and activity logging for teams willing to self-manage reliability and support.$q$, $q$The self-hosted Enterprise tier and the fully managed PagerDuty Process Automation SaaS tier are both custom-priced via PagerDuty sales, with third-party sources reporting average enterprise contract values around $51,000 per year.$q$]::text[], 2);
