-- Enrichment marathon batch: Rotato, Roundcube, Routine, Routr, RSS.com, RSSHub, RudderStack, Rundeck

-- ── Rotato ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Rotato is a Mac app that turns app screenshots and screen recordings into photorealistic 3D device mockup videos and images for product marketing.$q$, short_description),
  pricing_model = COALESCE($q$One-time lifetime license purchase across three tiers, plus a watermarked free trial (no ongoing subscription)$q$, pricing_model),
  starting_price = COALESCE($q$$79 one-time (Basic plan)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Small, self-funded indie team; bootstrapped and profitable with no outside investors$q$, company_size),
  headquarters = COALESCE($q$Zurich, Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Rotato Review 2026: Pricing, Features and 3D Mockup Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Rotato costs, which 3D device mockup and animation features it offers, and whether this Mac-only lifetime-license tool fits your product marketing workflow.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Rotato is a macOS application founded in 2019 by Morten, a former Google in-house incubator employee, that lets designers, marketers, and indie app makers turn plain screenshots or screen recordings into photorealistic 3D device mockup videos and images without needing skills in Cinema 4D, Blender, or After Effects. The company is based in Zurich, Switzerland, is self-funded and profitable, and has never raised outside investment, reporting over 150,000 installs in its own marketing materials. The core workflow lets a user drag a screenshot into a 3D scene, choose from more than 30 device mockups covering iPhone, iPad, MacBook, and Android hardware, position the device in real-time 3D space, adjust lighting and background, and set keyframes so the camera and screen content animate automatically between states such as rotating, floating, or zooming. Output formats include MP4, MOV, GIF, and static PNG, with resolution up to 4K on the Standard plan and 8K on the Premium plan; Premium additionally supports ProRes4444 with alpha-channel export for compositing in Premiere or Final Cut, plus HEVC/H.265. Rotato is sold as a one-time, lifetime-license purchase rather than a subscription, split into three tiers: Basic at $79 (phone mockups only, six months of free updates), Standard at $89 (the full 30-plus device library, one gallery template, 18 premium video templates, 12 months of updates, 4K export), and Premium at $199 (100 premium video templates, 50-plus gallery templates, two website templates, 8K export, a Figma plugin, clay-render mode, and camera lens controls, also with 12 months of updates). There is no permanent free tier, but a watermarked free trial is available before purchase. Rotato is Mac-only, with no native Windows or web version, which is the most consistently cited limitation in reviews. It is popular among SaaS founders and indie developers producing Product Hunt launch assets, App Store and Google Play preview videos, and landing-page hero visuals, as well as among design agencies and freelancers building UX presentation reels for clients. Competitors frequently compared to Rotato include Screen Studio and Matte, both of which use subscription pricing rather than Rotato's one-time-purchase model, a distinction Rotato emphasizes heavily as a selling point for buyers who prefer to avoid recurring software costs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fa4a289c-deca-4f77-9a17-9124d83266ee';

