-- ── Roundcube ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Roundcube is a free, open-source AJAX-based webmail client written in PHP that gives IMAP email a desktop-like browser interface.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (GNU GPL v3 or later); no official paid tiers, though hosting providers may bundle or manage it as part of paid hosting$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Italian$q$, $q$Chinese$q$]::text[],
  seo_title = COALESCE($q$Roundcube Webmail: Free Open-Source IMAP Email Client Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what Roundcube webmail is, its open-source history since 2008, core IMAP features, plugin ecosystem, and why it is free to self-host on any server.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Roundcube is a free and open-source, AJAX-based webmail client written in PHP that provides a desktop-like interface for reading and managing IMAP email accounts directly in a web browser. Development began in the mid-2000s under founder Thomas Bruederli, and the first stable release, version 0.1, was announced on March 4, 2008, after roughly two years of development; the project has been maintained continuously since. Roundcube is licensed under the GNU GPL version 3 or later, with exceptions that allow proprietary skins and plugins, and the codebase incorporates other open-source components such as the TinyMCE rich text editor, the Googiespell spell-checking library, and an HTML5-PHP sanitizer. It runs on a standard LAMP or LEMP stack (Linux, Apache or Nginx, MySQL/MariaDB or PostgreSQL, PHP) and requires no proprietary infrastructure, which is why it became a default bundled webmail option for many shared-hosting control panels; cPanel adopted Roundcube as its bundled webmail client, replacing SquirrelMail, and it remains commonly bundled with Plesk and DirectAdmin as well. In 2015, Roundcube and Kolab Systems AG announced plans for a full rewrite called Roundcube Next, backed by a crowdfunding campaign that raised US$103,541 against an $80,000 goal, but that rewrite effort was halted in 2016 and the original Roundcube codebase continued as the actively developed project. Since 2023, the project's fiscal and organizational home has been hosted under Nextcloud, which supports ongoing development and infrastructure. Core features include full IMAP support, an integrated address book, folder and message management, message search, spell checking, and MIME handling for attachments, and the interface is skinnable and extendable through a documented plugin API that lets administrators add features like two-factor authentication, calendaring (via plugins such as the Kolab-affiliated calendar plugin), or custom branding. Because it is free, self-hosted, and has no vendor lock-in, Roundcube is widely used by web hosts, universities, ISPs, and privacy-conscious organizations that want to run their own webmail front end on top of an existing IMAP/SMTP mail server rather than paying for a commercial hosted email suite. It has no company behind it in the traditional SaaS sense, no headquarters, and no per-seat pricing; costs to an organization are limited to hosting the software and optional support arrangements with third parties, since the core software itself remains permanently free under its open-source license.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'eb4553dc-a02b-4c01-a2c6-6a0dc57786d4';

