-- ── Routine ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Routine is an AI-powered productivity app that combines tasks, calendar, and notes into one workspace for individuals and teams.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription with individual and team tiers billed monthly$q$, pricing_model),
  starting_price = COALESCE($q$Free (Personal plan from $5/month, Professional from $10/month)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Small startup team, reported around 8 employees$q$, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Routine Review 2026: Pricing, Features and AI Task and Calendar Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore Routine's task, calendar, and notes workspace, its AI features, and pricing plans from free to Professional and Business tiers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Routine is a productivity application that merges task management, calendar scheduling, and note-taking into a single workspace, positioning itself against tools like Notion, Todoist, and standalone calendar apps. It was founded in 2020 in Paris, France by Quentin Hocquet and Julien Quintard, went through Y Combinator's Winter 2021 batch, and raised a $2.7 million pre-seed round backed by BoxGroup and Target Global along with angel investors including Clément Delangue and Ian Hogarth; company profile data lists the team at roughly eight employees. The product's interface is organized around an Inbox for quick capture of unplanned tasks, notes, and meeting invitations, an Agenda view for the current day, a Calendar that syncs with Google Calendar (with Outlook and iCloud support added over time), a structured Tasks list split into Unplanned, Recurring, and Upcoming sections, and a dedicated Notes space. Routine has increasingly emphasized AI features, including an AI assistant, AI voice commands, AI-generated meeting notes, and AI automations that act as agents within the workspace, consuming a monthly allotment of 'AI credits' that scales with plan tier. Routine is available on macOS, Windows, the web, and iOS, with Android support in progress as of its most recent public roadmap. Pricing follows a freemium model: the Free plan includes core tasks, calendar, and notes functionality, an AI assistant, offline mode, three integrations, three custom databases, and 250 AI credits per month at no cost. The Personal plan costs $5 per month and adds time blocking, time boxing, exporting, unlimited file uploads, ten integrations, ten custom databases, and 500 AI credits. The Professional plan costs $10 per month and adds AI meeting notes, AI agents, AI automations, a menu bar widget, time tracking, contextual capture, unlimited integrations and custom databases, and 7,000 AI credits. For teams, the Business plan is priced at $15 per seat per month and layers on organization-wide workspaces, access control, versioning, consolidated billing, priority support, and 10,000 AI credits per seat, while an Enterprise tier offers custom pricing with unlimited history, compliance controls, audit logs, analytics, user provisioning, and a dedicated success manager. All paid individual and Business plans can be canceled at any time, and Routine markets itself primarily to knowledge workers, freelancers, and small teams who want to consolidate calendar, task, and note tools that would otherwise require separate subscriptions to apps like Google Calendar, Todoist, and Notion.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '00e620ce-3d58-4944-af9e-bc0f5e8779e6';

