-- ── Routr ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Routr is a free, open-source SIP proxy, registrar, and location server built by Fonoster for deploying VoIP and telephony infrastructure on Docker and Kubernetes.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source, self-hosted; no official paid SaaS tier for Routr itself$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Routr (routr.io): Open-Source SIP Server for VoIP Infrastructure$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what Routr is, how this open-source SIP proxy, registrar, and location server from Fonoster works, and how it deploys on Docker and Kubernetes.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Routr, found at routr.io, is a lightweight, open-source SIP (Session Initiation Protocol) server that functions as a proxy, location server, and registrar for building reliable, scalable VoIP and telephony infrastructure. It is built and maintained by Fonoster, a company also known for its open-source alternative to Twilio's communications APIs, and the Routr codebase is publicly available on GitHub under the fonoster/routr repository, described there as 'the future of programmable SIP servers.' Routr is explicitly cloud-native: it is designed to run on Docker and Kubernetes (installable via Helm charts), as well as directly on major operating systems, so telephony carriers, communication service providers, and integrators can deploy SIP infrastructure without the operational complexity or licensing cost typically associated with traditional carrier-grade SIP servers. The server can be controlled through multiple interfaces, including a command-line tool for remote server management, a RESTful API for programmatic control, and a web-based GUI, which gives it flexibility for both manual administration and automated infrastructure-as-code workflows. Architecturally, Routr implements the standard SIP server roles of Proxy, Registrar, and Location Service, and supports configurable routing strategies such as Intra-Domain, Domain Ingress, Domain Egress, and Peer Egress routing, along with multi-tenant and multi-domain support backed by domain-level access control lists. Its modular design allows developers to extend functionality by writing custom Processors and Middleware, rather than being limited to the server's built-in behavior, which makes it suitable for teams that need to customize call routing logic for specific carrier or enterprise requirements. Because Routr is open source, it can be inspected, modified, and self-hosted freely, with no licensing fee for the software itself; organizations instead bear only their own infrastructure and, if desired, support costs. Routr is best understood as developer- and infrastructure-focused tooling rather than a consumer-facing product: its target users are telephony engineers, VoIP integrators, and communication service providers building or operating their own SIP-based calling infrastructure, often as a self-hosted alternative or complement to commercial SIP trunking and session border controller products. Given its open-source, community-driven nature, detailed corporate facts such as Fonoster's exact founding year, headquarters city, and team size are inconsistently reported across third-party company databases and are not confirmed here to avoid stating unverified figures.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6bf0f90f-c3ae-4dd2-8a3a-1395bd5e1b1c';

