-- ── RSSHub ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$RSSHub is a free, open-source RSS feed generator that creates RSS feeds from thousands of websites and services that do not natively offer one.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (AGPL-3.0 license); self-hostable, with free public community instances also available$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$Chinese$q$]::text[],
  seo_title = COALESCE($q$RSSHub: Free Open-Source RSS Feed Generator for Any Website$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what RSSHub is, how this open-source RSS feed generator with 1000+ routes and 5000+ instances works, and how to self-host or use public feeds.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RSSHub is a free, open-source RSS feed generator created and maintained by developer DIYgod, designed to make 'everything RSSible' by producing RSS feeds for websites, apps, and services that do not natively publish one. Released under the AGPL-3.0 license, the project's source code is hosted on GitHub at DIYgod/RSSHub and has accumulated more than 45,000 GitHub stars, reflecting its scale as one of the largest and most actively maintained open-source RSS tools. RSSHub describes itself as the world's largest RSS network, made up of more than 5,000 public instances run by community members, and its route library, built by more than 900 contributors and maintainers, covers over 1,000 pre-built routes spanning social media platforms, news sites, e-commerce listings, video platforms, forums, and many other categories of web content that would otherwise require manual checking. Because RSS feed support has declined across the modern web as many platforms drop native RSS in favor of closed apps and algorithmic feeds, RSSHub fills that gap by scraping or querying a source through code-defined 'routes' and outputting a standards-compliant RSS or Atom feed that any feed reader can subscribe to. Users can either run their own self-hosted RSSHub instance, using the official Docker image or npm package for full control and reliability, or use one of the many free public instances maintained by community members, trading some reliability and rate limits for zero setup effort. The project's ecosystem includes companion tools such as RSSHub Radar, a browser extension that detects RSS and RSSHub-compatible feeds on the page a user is currently viewing and offers one-click subscription, along with mobile counterparts RSSBud for iOS and RSSAid for Android built with Flutter. Because RSSHub is entirely open source and community-driven, there is no company behind it, no headquarters, and no official employee count; contributions and route maintenance come from a distributed volunteer community coordinated primarily through GitHub. RSSHub is popular among developers, researchers, journalists, and power users of RSS readers who want to track updates from sources such as social media accounts, government notices, price trackers, or niche blogs that lack an official feed, and it is frequently paired with self-hosted RSS reader software as part of a broader self-hosted or privacy-focused content-tracking stack.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '97ffdc76-9598-495d-a32e-3ec8c21cde65';

