-- ── RudderStack ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$RudderStack is a warehouse-native customer data platform that collects, unifies, and routes customer event data to a company's own data warehouse and downstream tools.$q$, short_description),
  pricing_model = COALESCE($q$Usage-based subscription with a free tier based on monthly event volume, plus Growth and custom Enterprise plans$q$, pricing_model),
  starting_price = COALESCE($q$Free (250K events/month); Growth plan from $265/month$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Approximately 130 employees (reported range of 127 to 150 across sources)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$RudderStack Review 2026: Pricing, Features and Warehouse-Native CDP$q$, seo_title),
  seo_meta_description = COALESCE($q$See how RudderStack's warehouse-native customer data platform works, its event volume-based pricing tiers, and its core data collection and activation features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RudderStack is a warehouse-native customer data platform (CDP) founded in July 2019 by CEO Soumyadeb Mitra and Executive Chairman Shvetank Jain, headquartered in San Francisco, California. Unlike traditional CDPs that store customer data in a proprietary system, RudderStack is built around the idea of running data collection, identity resolution, and activation directly on top of a customer's own data warehouse, such as Snowflake, BigQuery, Databricks, or Redshift, so companies retain ownership and control of their data rather than duplicating it into a vendor-hosted store. The platform originated as an open-source project and remains open source at its core, alongside a hosted commercial offering, giving engineering teams the option to self-host or use RudderStack's managed cloud service. Its core capabilities span three areas: event collection through more than a dozen SDKs across web, mobile, and server environments; routing of that event data to more than 200 supported cloud destinations, such as marketing, analytics, and advertising tools; and reverse ETL, which activates data already modeled in the warehouse by syncing it back out to operational and go-to-market tools. RudderStack's pricing is usage-based and tied to monthly event volume. The Free plan supports up to 250,000 events per month and includes access to 16 SDK sources, 200-plus cloud destinations, warehouse destinations, reverse ETL, one tracking plan, a five-transformation limit, up to 10 team members, and a single production workspace, all at no cost. The Growth plan starts at $265 per month for up to 1 million events (scalable to 25 million-plus with added spend), offers a 15 percent discount for annual commitments, and adds unlimited team members, unlimited tracking plans, 30-minute warehouse sync intervals, two workspaces, 25 reverse ETL connections, a 25-transformation limit, advanced consent management integration, dedicated Slack support, and up to six months of onboarding assistance. The custom-priced Enterprise plan is aimed at large organizations and includes everything in Growth plus 5-minute warehouse sync, unlimited transformations, access to RudderStack's Profiles and Data Apps features, HIPAA compliance support, single sign-on, VPC deployment options, and white-glove support with a dedicated Technical Account Manager, Customer Success Manager, and Solutions Architect. Company-size estimates place RudderStack at roughly 127 to 150 employees as of 2026, spread across North America, Europe, and Asia. RudderStack is most commonly adopted by data engineering and analytics teams at mid-market and enterprise companies that want first-party, warehouse-native customer data infrastructure as a more controllable and cost-predictable alternative to legacy CDPs like Segment.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'db57c4c5-6372-4dcb-8aeb-de596d7f6b20';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = 'db57c4c5-6372-4dcb-8aeb-de596d7f6b20' AND logo IS NULL AND website IS NOT NULL;

