-- ── Rundeck ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Rundeck is runbook automation and job scheduling software for operations teams, now owned by PagerDuty as part of its Process Automation product line.$q$, short_description),
  pricing_model = COALESCE($q$Open-core: free open-source Community Edition, with a commercially licensed Enterprise/Process Automation tier priced via custom quote$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition); Enterprise pricing custom, industry-reported to average around $51,000/year$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Operated as part of PagerDuty, Inc. (NYSE: PD), a public company; standalone Rundeck team size not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (part of PagerDuty, Inc.)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Rundeck Review 2026: Pricing, Features and PagerDuty Ownership Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn how Rundeck's runbook automation and job scheduling platform works, its free Community Edition versus paid Enterprise tier, and its PagerDuty acquisition.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Rundeck is runbook automation and job scheduling software originally released in 2010 by SimplifyOps, a company formally founded in 2013 by Damon Edwards, Alex Honor, and Greg Schueler, the same people behind the open-source Rundeck project. Rundeck was built to let operations teams automate routine maintenance tasks and delegate controlled access to run specific jobs without granting broad system access, effectively turning manual runbooks into repeatable, auditable, self-service automations. On October 1, 2020, Rundeck was acquired by PagerDuty, the publicly traded incident-response and operations company (NYSE: PD), for approximately $100 million in a mix of cash and stock; PagerDuty has stated that the acquisition did not change pricing for its existing PagerDuty products, and Rundeck continues to be offered as a distinct product line, now marketed as PagerDuty Process Automation. Rundeck's job scheduling system supports both cron-style scheduled jobs and event-driven triggers, and its workflow engine handles multi-step operational processes with conditional logic, error handling, retry mechanisms, and parallel step execution across distributed infrastructure. The product is offered in three tiers: the open-source Community Edition, which is free and includes core workflow execution, community plugins, encryption, scheduling, activity logging, and key storage; a self-hosted Enterprise edition (PagerDuty Process Automation Self-Hosted), which adds high-availability clustering with auto-takeover, single sign-on authentication, certified enterprise plugins for tools like PagerDuty, ServiceNow, and Datadog, enhanced rule-based webhooks, a workflow visualization and configuration GUI, and job queuing and load balancing for scale; and a fully managed SaaS edition (PagerDuty Process Automation), which adds a 99.9 percent uptime SLA managed directly by PagerDuty along with AI-assisted runbook generation and ROI metrics. Neither the self-hosted Enterprise nor the SaaS tier publishes list pricing; both require contacting PagerDuty sales for a custom quote, though third-party industry sources have reported average enterprise contract values around $51,000 per year. Because Rundeck is now a PagerDuty product, standalone company size and revenue figures are not separately disclosed; PagerDuty as a whole is a publicly traded company. Rundeck's core users are IT operations, DevOps, and site reliability engineering teams at organizations, including many Fortune 500 companies, that need to standardize and delegate operational tasks like server restarts, deployments, and incident remediation steps without giving every engineer full production access.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e0fb3e39-f5c6-463d-becd-ea6bca2dd8bd';

